const item = $input.first();
const body = item.json.body ?? item.json;
const shotId = body.shot_id;
if (!shotId) {
  throw new Error('shot_id is required');
}

const backendBaseUrl = $env.BACKEND_BASE_URL;
if (!backendBaseUrl) {
  throw new Error('BACKEND_BASE_URL is required');
}

const shot = await $helpers.httpRequest({
  method: 'GET',
  url: `${backendBaseUrl}/api/shots/${shotId}`,
  json: true,
});

const fields = shot.fields ?? {};
return [{
  json: {
    ok: true,
    workflow: 'expand-shot',
    shot_id: fields.shot_id ?? shotId,
    treatment_id: fields.treatment_id ?? null,
    title: fields.title ?? null,
    image_path: fields.image_path ?? null,
    routing: fields.routing ?? null,
    failure_axes: fields.failure_axes ?? null,
    expansion_type: fields.expansion_type ?? null,
    expander_used: fields.expander_used ?? false,
    message: 'Shot payload prepared for expansion workflow'
  }
}];
